+      const titleLooksLikePrompt = title.includes('/') ||
+                                    title.startsWith('~') ||
+                                    title === '';
+      if (!titleLooksLikePrompt && title.length > 0) {
+        // Title looks like a running command - show folder + asterisk
+        indicator = '📁 *';
+      } else {
+        // At prompt - just show folder, no dot or asterisk
